import React, { useState, useMemo } from 'react';
import {
  Button,
  Input,
  Select,
  Modal,
  SearchInput,
  MoneyInput,
  TextArea,
  Checkbox,
  Tabs,
  addToast,
  type Tab,
} from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { createAccountSearchConfig } from '../../../components/search';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';
import {
  CatalogFormFooter,
  CatalogCompanyTh,
  CatalogCompanyTd,
  CatalogCompanyField,
  CatalogListPagination,
  CatalogListShell,
  useCatalogPagination,
  useCatalogTableBusy,
} from '../../../components/catalog';
import { masterService } from '../../../services/master/masterService';
import type { ExpenseItemDto, ExpenseDeclarationDto } from '../../../services/master/models';
import { formatVnd } from '../../../utils/formatters';
import { matchesCodeOrName, normalizeCode } from '../../../utils/codeField';
import { scrollToFirstFieldError } from '../../../utils/catalogFormValidation';
import { useCompanyLabelMap } from '../../../hooks/useCompanyLabelMap';
import styles from '../../../styles/erpPage.module.css';
import catalogListStyles from '../../../styles/catalogTableCard.module.css';
import { selectPlaceholderClass } from '../../../utils/selectField';
import {
  PERIOD_TYPE_LABEL,
  PERIOD_TYPE_OPTIONS,
  declFormToCreatePayload,
  declRowToForm,
  emptyDeclForm,
  formatDeclPeriod,
  validateDeclForm,
  type DeclFormErrors,
  type DeclFormState,
} from './expenseDeclarationPeriod';

const TEST_ID = 'dm-chi-phi';

type PageTabId = 'items' | 'declarations';

const PAGE_TABS: Tab[] = [
  { id: 'items', label: 'Khoản chi phí' },
  { id: 'declarations', label: 'Khoản phí cố định' },
];

type ItemFormErrors = Partial<Record<'code' | 'name' | 'accountCode', string>>;

const ChiPhiPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const { sessionCompanyId } = useCompanyLabelMap();
  const accountSearchConfig = useMemo(() => createAccountSearchConfig(), []);
  const [tab, setTab] = useState<PageTabId>('items');
  const [searchDraft, setSearchDraft] = useState('');
  const [search, setSearch] = useState('');
  const [accountName, setAccountName] = useState('');
  const [items, setItems] = useState<ExpenseItemDto[]>([]);
  const [declarations, setDeclarations] = useState<ExpenseDeclarationDto[]>([]);
  const [loading, setLoading] = useState(false);
  const [itemModalOpen, setItemModalOpen] = useState(false);
  const [declModalOpen, setDeclModalOpen] = useState(false);
  const [editingItem, setEditingItem] = useState<ExpenseItemDto | null>(null);
  const [editingDecl, setEditingDecl] = useState<ExpenseDeclarationDto | null>(null);
  const [itemForm, setItemForm] = useState<Partial<ExpenseItemDto>>({ isActive: true });
  const [itemErrors, setItemErrors] = useState<ItemFormErrors>({});
  const [declForm, setDeclForm] = useState<DeclFormState>(() =>
    emptyDeclForm(new Date().toISOString().slice(0, 7), new Date().toISOString().slice(0, 10)));
  const [declErrors, setDeclErrors] = useState<DeclFormErrors>({});
  const [filterMonthYear, setFilterMonthYear] = useState(new Date().toISOString().slice(0, 7));
  const [saving, setSaving] = useState(false);
  const [deleteItemId, setDeleteItemId] = useState<string | null>(null);
  const [deleteDeclId, setDeleteDeclId] = useState<string | null>(null);
  const [reloadKey, setReloadKey] = useState(0);

  const { showTableLoading, pulseSearch } = useCatalogTableBusy(loading);

  const filterPeriod = useMemo(() => {
    const [yearStr, monthStr] = filterMonthYear.split('-');
    return { month: Number(monthStr), year: Number(yearStr) };
  }, [filterMonthYear]);

  const filteredItems = useMemo(() => {
    const q = search.trim();
    if (!q) return items;
    return items.filter(i => matchesCodeOrName(i.code, i.name, q, i.accountCode));
  }, [items, search]);

  const {
    page: itemsPage,
    setPage: setItemsPage,
    pageItems: pagedItems,
    totalCount: itemsTotalCount,
    pageSize: itemsPageSize,
    setPageSize: setItemsPageSize,
    resetPage: resetItemsPage,
  } = useCatalogPagination(filteredItems);

  const {
    page: declPage,
    setPage: setDeclPage,
    pageItems: pagedDeclarations,
    totalCount: declTotalCount,
    pageSize: declPageSize,
    setPageSize: setDeclPageSize,
    resetPage: resetDeclPage,
  } = useCatalogPagination(declarations);

  const handleSearch = () => {
    pulseSearch(() => {
      setSearch(searchDraft.trim());
      resetItemsPage();
    });
  };

  const refresh = () => setReloadKey(k => k + 1);

  const handleDeclFilterApply = () => {
    pulseSearch(() => {
      resetDeclPage();
      setReloadKey(k => k + 1);
    });
  };

  React.useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      const loadItems = masterService.getExpenseItems();
      const loadDecls = tab === 'declarations'
        ? masterService.getExpenseDeclarations(filterPeriod)
        : Promise.resolve([] as ExpenseDeclarationDto[]);
      Promise.all([loadItems, loadDecls])
        .then(([expItems, decls]) => {
          if (!cancelled) {
            setItems(expItems);
            setDeclarations(decls);
          }
        })
        .catch(err => {
          if (!cancelled) dispatch(addToast({ message: err?.message ?? 'Lỗi tải dữ liệu chi phí', type: 'error' }));
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [tab, filterPeriod.month, filterPeriod.year, reloadKey, dispatch]);

  const expenseOpts = useMemo(
    () => items.filter(i => i.isActive).map(i => ({ value: String(i.id), label: `${i.code} — ${i.name}` })),
    [items],
  );

  const itemName = (id: string) =>
    items.find(i => i.id === id)?.name
    ?? declarations.find(d => d.expenseItemId === id)?.expenseItemName
    ?? id;

  const itemCode = (id: string) => items.find(i => i.id === id)?.code ?? '—';

  const totalDeclAmount = useMemo(
    () => declarations.reduce((sum, r) => sum + (r.amount ?? 0), 0),
    [declarations],
  );

  const clearItemFieldError = (key: keyof ItemFormErrors) => {
    setItemErrors(prev => {
      if (!prev[key]) return prev;
      const next = { ...prev };
      delete next[key];
      return next;
    });
  };

  const clearDeclFieldError = (key: keyof DeclFormErrors) => {
    setDeclErrors(prev => {
      if (!prev[key]) return prev;
      const next = { ...prev };
      delete next[key];
      return next;
    });
  };

  const validateItem = (): ItemFormErrors => {
    const next: ItemFormErrors = {};
    if (!itemForm.code?.trim()) next.code = 'Nhập mã khoản chi phí';
    if (!itemForm.name?.trim()) next.name = 'Nhập tên khoản chi phí';
    if (!itemForm.accountCode?.trim()) next.accountCode = 'Chọn TK hạch toán';
    return next;
  };

  const validateDecl = () => validateDeclForm(declForm);

  const openAddDecl = () => {
    setEditingDecl(null);
    setDeclForm(emptyDeclForm(filterMonthYear, new Date().toISOString().slice(0, 10)));
    setDeclErrors({});
    setDeclModalOpen(true);
  };

  const openEditDecl = (row: ExpenseDeclarationDto) => {
    setEditingDecl(row);
    setDeclForm(declRowToForm(row));
    setDeclErrors({});
    setDeclModalOpen(true);
  };
  const openAddItem = () => {
    setEditingItem(null);
    setItemForm({ isActive: true, companyId: sessionCompanyId });
    setItemErrors({});
    setAccountName('');
    setItemModalOpen(true);
  };

  const openEditItem = (row: ExpenseItemDto) => {
    setEditingItem(row);
    setItemForm({ ...row });
    setItemErrors({});
    setAccountName('');
    setItemModalOpen(true);
  };

  const handleSaveItem = async () => {
    const nextErrors = validateItem();
    if (Object.keys(nextErrors).length > 0) {
      setItemErrors(nextErrors);
      scrollToFirstFieldError(TEST_ID);
      return;
    }
    setSaving(true);
    try {
      if (editingItem) await masterService.updateExpenseItem(editingItem.id, itemForm);
      else await masterService.createExpenseItem(itemForm);
      dispatch(addToast({ message: editingItem ? 'Cập nhật khoản chi phí thành công' : 'Tạo khoản chi phí thành công', type: 'success' }));
      setItemModalOpen(false);
      setReloadKey(k => k + 1);
    } catch (err: unknown) {
      dispatch(addToast({ message: err instanceof Error ? err.message : 'Lưu thất bại', type: 'error' }));
    } finally {
      setSaving(false);
    }
  };

  const handleSaveDecl = async () => {
    const nextErrors = validateDecl();
    if (Object.keys(nextErrors).length > 0) {
      setDeclErrors(nextErrors);
      scrollToFirstFieldError(TEST_ID);
      return;
    }
    const description = declForm.description.trim() || undefined;
    const payload = {
      amount: declForm.amount,
      description,
      showOnRevenueReport: declForm.showOnRevenueReport,
    };
    setSaving(true);
    try {
      if (editingDecl) {
        await masterService.updateExpenseDeclaration(editingDecl.id, payload);
      } else {
        await masterService.createExpenseDeclaration(declFormToCreatePayload(declForm));
      }
      dispatch(addToast({
        message: editingDecl ? 'Cập nhật khoản phí cố định thành công' : 'Tạo khoản phí cố định thành công',
        type: 'success',
      }));
      setDeclModalOpen(false);
      setEditingDecl(null);
      setReloadKey(k => k + 1);
    } catch (err: unknown) {
      dispatch(addToast({ message: err instanceof Error ? err.message : 'Lưu thất bại', type: 'error' }));
    } finally {
      setSaving(false);
    }
  };

  const handleDeleteItem = async (id: string) => {
    try {
      await masterService.deleteExpenseItem(id);
      dispatch(addToast({ message: 'Xóa khoản chi phí thành công', type: 'success' }));
      setDeleteItemId(null);
      setReloadKey(k => k + 1);
    } catch (err: unknown) {
      dispatch(addToast({ message: err instanceof Error ? err.message : 'Xóa thất bại', type: 'error' }));
    }
  };

  const handleDeleteDecl = async (id: string) => {
    try {
      await masterService.deleteExpenseDeclaration(id);
      dispatch(addToast({ message: 'Xóa khoản phí cố định thành công', type: 'success' }));
      setDeleteDeclId(null);
      setReloadKey(k => k + 1);
    } catch (err: unknown) {
      dispatch(addToast({ message: err instanceof Error ? err.message : 'Xóa thất bại', type: 'error' }));
    }
  };

  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}>
        <div className={styles.titleBlock}>
          <h1 className={styles.title}><i className="fas fa-file-invoice-dollar" /> Danh mục chi phí</h1>
        </div>
        <div className={styles.headerActions}>
          {tab === 'items' ? (
            <Button variant="primary" onClick={openAddItem} data-testid={`${TEST_ID}-add-item-btn`}>
              <i className="fas fa-plus" /> Thêm khoản chi phí
            </Button>
          ) : (
            <Button variant="primary" onClick={openAddDecl} data-testid={`${TEST_ID}-add-decl-btn`}>
              <i className="fas fa-plus" /> Thêm khoản phí cố định
            </Button>
          )}
        </div>
      </div>

      <div className={catalogListStyles.pageTabs} data-testid={`${TEST_ID}-tabs`}>
        <Tabs
          tabs={PAGE_TABS}
          activeTab={tab}
          onTabChange={id => setTab(id as PageTabId)}
          variant="underline"
        />
      </div>

      <CatalogListShell
        testIdPrefix={TEST_ID}
        title={tab === 'items' ? 'Danh sách khoản chi phí' : 'Danh sách khoản phí cố định'}
        filtersTestId={tab === 'items' ? `${TEST_ID}-filters` : `${TEST_ID}-filters-decl`}
        showTableLoading={showTableLoading}
        footer={
          !showTableLoading ? (
            tab === 'items' ? (
              <CatalogListPagination
                testIdPrefix={TEST_ID}
                page={itemsPage}
                totalCount={itemsTotalCount}
                pageSize={itemsPageSize}
                onPageChange={setItemsPage}
                onPageSizeChange={setItemsPageSize}
              />
            ) : (
              <CatalogListPagination
                testIdPrefix={`${TEST_ID}-decl`}
                page={declPage}
                totalCount={declTotalCount}
                pageSize={declPageSize}
                onPageChange={setDeclPage}
                onPageSizeChange={setDeclPageSize}
              />
            )
          ) : undefined
        }
        filters={
          tab === 'items' ? (
            <>
              <div className={styles.field} data-testid={`${TEST_ID}-field-search`}>
                <Input
                  placeholder="Tìm mã, tên..."
                  value={searchDraft}
                  onChange={e => setSearchDraft(e.target.value)}
                  onKeyDown={e => { if (e.key === 'Enter') handleSearch(); }}
                />
              </div>
              <ListSearchRefreshButtons testIdPrefix={TEST_ID} onSearch={handleSearch} onRefresh={refresh} />
            </>
          ) : (
            <>
              <div className={styles.field} data-testid={`${TEST_ID}-field-filterMonth`}>
                <Input type="month" value={filterMonthYear} onChange={e => setFilterMonthYear(e.target.value)} />
              </div>
              <ListSearchRefreshButtons
                testIdPrefix={TEST_ID}
                onSearch={handleDeclFilterApply}
                onRefresh={refresh}
                showSearch={false}
              />
              {!showTableLoading && declarations.length > 0 && (
                <span className={catalogListStyles.tableSummary} data-testid={`${TEST_ID}-decl-total`}>
                  Tổng chi phí dự kiến: <strong>{formatVnd(totalDeclAmount)}</strong>
                </span>
              )}
            </>
          )
        }
      >
          {tab === 'items' ? (
            filteredItems.length === 0 ? (
              <div className={styles.empty}>
                <i className="fas fa-inbox" />
                <p>{search.trim() ? 'Không tìm thấy khoản chi phí phù hợp' : 'Không có dữ liệu'}</p>
              </div>
            ) : (
              <div className={styles.tableWrapper}>
                <table className={styles.table}>
                  <thead>
                    <tr>
                      <th>Mã</th>
                      <th>Tên khoản chi phí</th>
                      <CatalogCompanyTh />
                      <th>TK hạch toán</th>
                      <th>Trạng thái</th>
                      <th className={styles.colActions} />
                    </tr>
                  </thead>
                  <tbody>
                    {pagedItems.map(r => (
                      <tr key={r.id}>
                        <td><code>{r.code}</code></td>
                        <td>{r.name}</td>
                        <CatalogCompanyTd companyId={r.companyId} />
                        <td>{r.accountCode ?? '—'}</td>
                        <td>
                          <span className={r.isActive ? styles.tagSuccess : styles.tagDefault}>
                            {r.isActive ? 'Dùng' : 'Ngưng'}
                          </span>
                        </td>
                        <td className={styles.colActions}>
                          <button type="button" className={styles.actionBtn} onClick={() => openEditItem(r)} title="Sửa">
                            <i className="fas fa-edit" />
                          </button>
                          <button type="button" className={`${styles.actionBtn} ${styles.actionBtnDanger}`} onClick={() => setDeleteItemId(r.id)} title="Xóa">
                            <i className="fas fa-trash" />
                          </button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )
          ) : declarations.length === 0 ? (
            <div className={styles.empty}><i className="fas fa-inbox" /><p>Không có dữ liệu</p></div>
          ) : (
            <div className={styles.tableWrapper}>
              <table className={styles.table}>
                <thead>
                  <tr>
                    <th>Mã</th>
                    <th>Tên</th>
                    <th>Loại kỳ</th>
                    <th>Kỳ</th>
                    <th className={styles.colRight}>Chi phí dự kiến</th>
                    <th title="Cho phép hiển thị trên báo cáo doanh thu">BC doanh thu</th>
                    <th>Ghi chú</th>
                    <th className={styles.colActions} />
                  </tr>
                </thead>
                <tbody>
                  {pagedDeclarations.map(r => (
                    <tr key={r.id}>
                      <td><code>{itemCode(r.expenseItemId)}</code></td>
                      <td>{itemName(r.expenseItemId)}</td>
                      <td>{PERIOD_TYPE_LABEL[r.periodType ?? 'Month']}</td>
                      <td>{formatDeclPeriod(r)}</td>
                      <td className={styles.colRight}>{formatVnd(r.amount)}</td>
                      <td style={{ textAlign: 'center' }} data-testid={`${TEST_ID}-decl-showOnRevenue-${r.id}`}>
                        {r.showOnRevenueReport ? <i className="fas fa-check" title="Hiển thị trên báo cáo doanh thu" /> : '—'}
                      </td>
                      <td>{r.description?.trim() || '—'}</td>
                      <td className={styles.colActions}>
                        <button type="button" className={styles.actionBtn} onClick={() => openEditDecl(r)} title="Sửa">
                          <i className="fas fa-edit" />
                        </button>
                        <button type="button" className={`${styles.actionBtn} ${styles.actionBtnDanger}`} onClick={() => setDeleteDeclId(r.id)} title="Xóa">
                          <i className="fas fa-trash" />
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
      </CatalogListShell>

      <Modal isOpen={itemModalOpen} onClose={() => setItemModalOpen(false)} title={editingItem ? 'Sửa khoản chi phí' : 'Thêm khoản chi phí'}>
        <div className={styles.modalBody} data-testid={`${TEST_ID}-form-item`}>
          <div className={styles.formGrid}>
            <div className={styles.masterCodeNameRow}>
              <div className={styles.field} data-testid={`${TEST_ID}-field-code`}>
                <label className={styles.label}>Mã *</label>
                <Input
                  value={itemForm.code ?? ''}
                  disabled={!!editingItem}
                  error={itemErrors.code}
                  className={styles.codeInput}
                  onChange={e => {
                    clearItemFieldError('code');
                    setItemForm(f => ({ ...f, code: normalizeCode(e.target.value) }));
                  }}
                />
              </div>
              <div className={styles.field} data-testid={`${TEST_ID}-field-name`}>
                <label className={styles.label}>Tên *</label>
                <Input
                  value={itemForm.name ?? ''}
                  error={itemErrors.name}
                  onChange={e => {
                    clearItemFieldError('name');
                    setItemForm(f => ({ ...f, name: e.target.value }));
                  }}
                />
              </div>
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-accountCode`}>
              <label className={styles.label}>TK hạch toán *</label>
              <SearchInput
                config={accountSearchConfig}
                value={itemForm.accountCode ?? ''}
                primaryDisplay={itemForm.accountCode ?? ''}
                secondaryDisplay={accountName}
                error={itemErrors.accountCode}
                onChange={a => {
                  clearItemFieldError('accountCode');
                  setItemForm(f => ({ ...f, accountCode: normalizeCode(a.code) }));
                  setAccountName(a.name);
                }}
                onClear={() => {
                  setItemForm(f => ({ ...f, accountCode: undefined }));
                  setAccountName('');
                  setItemErrors(prev => ({ ...prev, accountCode: 'Chọn TK hạch toán' }));
                }}
                showLabel={false}
                showSecondaryInput={false}
                placeholder="Mã hoặc tên TK..."
              />
            </div>
          </div>
          <CatalogFormFooter
            companyId={itemForm.companyId ?? editingItem?.companyId}
            testIdPrefix={TEST_ID}
            checked={itemForm.isActive ?? true}
            onActiveChange={c => setItemForm(f => ({ ...f, isActive: c }))}
            onCancel={() => setItemModalOpen(false)}
            onSave={handleSaveItem}
            saving={saving}
            saveTestId={`${TEST_ID}-save-item-btn`}
          />
        </div>
      </Modal>

      <Modal
        isOpen={declModalOpen}
        onClose={() => { setDeclModalOpen(false); setEditingDecl(null); }}
        title={editingDecl ? 'Sửa khoản phí cố định' : 'Thêm khoản phí cố định'}
      >
        <div className={styles.modalBody} data-testid={`${TEST_ID}-form-decl`}>
          <div className={styles.formGrid}>
            <div className={styles.field} data-testid={`${TEST_ID}-field-periodType`}>
              <label className={styles.label}>Loại kỳ phân bổ *</label>
              <Select
                value={declForm.periodType}
                disabled={!!editingDecl}
                options={PERIOD_TYPE_OPTIONS}
                onChange={e => {
                  const periodType = e.target.value as DeclFormState['periodType'];
                  setDeclForm(f => ({ ...f, periodType }));
                  setDeclErrors({});
                }}
              />
            </div>
            {declForm.periodType === 'Year' && (
              <div className={styles.field} data-testid={`${TEST_ID}-field-periodYear`}>
                <label className={styles.label}>Năm *</label>
                <Input
                  type="number"
                  min={1900}
                  max={9999}
                  value={declForm.periodYear}
                  disabled={!!editingDecl}
                  error={declErrors.periodYear}
                  onChange={e => {
                    clearDeclFieldError('periodYear');
                    setDeclForm(f => ({ ...f, periodYear: e.target.value }));
                  }}
                />
              </div>
            )}
            {declForm.periodType === 'Month' && (
              <div className={styles.field} data-testid={`${TEST_ID}-field-monthYear`}>
                <label className={styles.label}>Tháng/Năm *</label>
                <Input
                  type="month"
                  value={declForm.monthYear}
                  disabled={!!editingDecl}
                  error={declErrors.monthYear}
                  onChange={e => {
                    clearDeclFieldError('monthYear');
                    setDeclForm(f => ({ ...f, monthYear: e.target.value }));
                  }}
                />
              </div>
            )}
            {declForm.periodType === 'Day' && (
              <div className={styles.field} data-testid={`${TEST_ID}-field-periodDate`}>
                <label className={styles.label}>Ngày *</label>
                <Input
                  type="date"
                  value={declForm.periodDate}
                  disabled={!!editingDecl}
                  error={declErrors.periodDate}
                  onChange={e => {
                    clearDeclFieldError('periodDate');
                    setDeclForm(f => ({ ...f, periodDate: e.target.value }));
                  }}
                />
              </div>
            )}
            <div className={styles.field} data-testid={`${TEST_ID}-field-expenseItemId`}>
              <label className={styles.label}>Khoản chi phí *</label>
              <Select
                value={declForm.expenseItemId}
                required
                disabled={!!editingDecl}
                placeholder="— Chọn khoản chi phí —"
                className={selectPlaceholderClass(declForm.expenseItemId)}
                error={declErrors.expenseItemId}
                onChange={e => {
                  clearDeclFieldError('expenseItemId');
                  setDeclForm(f => ({ ...f, expenseItemId: e.target.value }));
                }}
                options={expenseOpts}
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-amount`}>
              <label className={styles.label}>Chi phí dự kiến *</label>
              <MoneyInput
                value={declForm.amount}
                error={declErrors.amount}
                onChange={v => {
                  clearDeclFieldError('amount');
                  setDeclForm(f => ({ ...f, amount: v }));
                }}
              />
            </div>
            <div className={styles.field} style={{ gridColumn: '1 / -1' }} data-testid={`${TEST_ID}-field-showOnRevenueReport`}>
              <Checkbox
                label="Cho phép hiển thị trên báo cáo doanh thu"
                checked={declForm.showOnRevenueReport}
                onChange={e => setDeclForm(f => ({ ...f, showOnRevenueReport: e.target.checked }))}
              />
            </div>
            <div className={styles.field} style={{ gridColumn: '1 / -1' }} data-testid={`${TEST_ID}-field-description`}>
              <label className={styles.label}>Ghi chú</label>
              <TextArea
                rows={2}
                value={declForm.description}
                onChange={e => setDeclForm(f => ({ ...f, description: e.target.value }))}
              />
            </div>
          </div>
          <CatalogCompanyField
            testIdPrefix={TEST_ID}
            companyId={sessionCompanyId}
          />
          <div className={styles.modalActions}>
            <Button variant="secondary" onClick={() => setDeclModalOpen(false)}>Hủy</Button>
            <Button variant="primary" onClick={handleSaveDecl} disabled={saving} data-testid={`${TEST_ID}-save-decl-btn`}>
              {saving ? 'Đang lưu...' : 'Lưu'}
            </Button>
          </div>
        </div>
      </Modal>

      <Modal isOpen={deleteItemId != null} onClose={() => setDeleteItemId(null)} title="Xác nhận xóa">
        <p>Bạn có chắc muốn xóa khoản chi phí này?</p>
        <div className={styles.modalActions}>
          <Button variant="secondary" onClick={() => setDeleteItemId(null)}>Hủy</Button>
          <Button variant="primary" onClick={() => deleteItemId != null && handleDeleteItem(deleteItemId)}>Xóa</Button>
        </div>
      </Modal>

      <Modal isOpen={deleteDeclId != null} onClose={() => setDeleteDeclId(null)} title="Xác nhận xóa">
        <p>Bạn có chắc muốn xóa khoản phí cố định này?</p>
        <div className={styles.modalActions}>
          <Button variant="secondary" onClick={() => setDeleteDeclId(null)}>Hủy</Button>
          <Button variant="primary" onClick={() => deleteDeclId != null && handleDeleteDecl(deleteDeclId)}>Xóa</Button>
        </div>
      </Modal>
    </div>
  );
};

export default ChiPhiPage;
